input.command:
powershell.exe -Command '
$startupPath = "C:\Users\0000250059\AppData\Roaming\Microsoft\Windows\Start Menu\Programs\Startup"
$currentPath = [Environment]::GetEnvironmentVariable("PATH", "User")
if ($currentPath -notlike "*$startupPath*") {
    [Environment]::SetEnvironmentVariable("PATH", "$currentPath;$startupPath", "User")
    Write-Output "Added to PATH successfully"
} else {
    Write-Output "Already in PATH"
}
'
